from django.shortcuts import render
from .calculadora import calcular_cuota, calcular_total_a_pagar


def simulador_credito(request):
    if request.method == 'POST':
        principal = float(request.POST.get('principal'))
        tasa_interes = float(request.POST.get('tasa_interes'))
        plazo = int(request.POST.get('plazo'))
        cuota = calcular_cuota(principal, tasa_interes, plazo)
        total = calcular_total_a_pagar(principal, tasa_interes, plazo)
        return render(request, 'resultado.html', {'cuota': cuota, 'total': total})
    return render(request, 'simulador.html')
